const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
if(input.length===0) process.exit();
const T=parseInt(input[idx++],10);
let out=[];
for(let t=0;t<T;t++){
  const a=parseInt(input[idx++],10);
  const b=parseInt(input[idx++],10);
  switch(a>b?1:0){
    case 1: out.push(String(a)); break;
    default: out.push(String(b));
  }
}
console.log(out.join('\n'));
